t.script:
document.addEventListener('DOMContentLoaded', function () {
var searchInput = document.querySelector('.prq-job-search');
var searchBtn = document.querySelector('.prq-search-btn');
var jobCards = document.querySelectorAll('.prq-job-card');

function filterJobs(query) {
query = (query || '').toLowerCase();
jobCards.forEach(function (card) {
var title = (card.querySelector('.prq-job-title') || {}).textContent || '';
var company = (card.querySelector('.prq-job-company') || {}).textContent || '';
var meta = (card.querySelector('.job-meta') || {}).textContent || '';
var combined = (title + ' ' + company + ' ' + meta).toLowerCase();
card.style.display = combined.indexOf(query) !== -1 ? 'block' : 'none';
});
}

if (searchInput) {
searchInput.addEventListener('input', function (e) { filterJobs(e.target.value); });
}
if (searchBtn) {
searchBtn.addEventListener('click', function () {
filterJobs(searchInput ? searchInput.value : '');
});
}
});

document.addEventListener('DOMContentLoaded', function () {
var errorClose = document.getElementById('prqErrorClose');
if (errorClose) {
errorClose.addEventListener('click', function () {
var popup = document.getElementById('prqErrorPopup');
if (popup) popup.remove();
});
}

var form = document.querySelector('.prq-form-grid');
if (form) {
form.addEventListener('submit', function () {
var btn = this.querySelector('.prq-submit-btn');
if (btn) {
btn.innerHTML = ' Submitting...';
btn.style.transform = 'scale(1.05)';
}
});
}

var input = document.querySelector('input[name="partner_location"]');
var list = document.getElementById('job-location-suggestions');
if (!input || !list) return;

var timer = null;

list.addEventListener('click', function (ev) {
var target = ev.target.closest('.prq-suggestion-item');
if (!target) return;
input.value = target.dataset.value || target.textContent || '';
list.innerHTML = '';
});

input.addEventListener('blur', function () {
window.setTimeout(function () { list.innerHTML = ''; }, 150);
});

input.addEventListener('input', function () {
var term = input.value.trim();
window.clearTimeout(timer);
if (term.length < 2) { list.innerHTML = ''; return; }
timer = window.setTimeout(function () {
fetch('/jobs/location_suggest', {
method: 'POST',
headers: {'Content-Type': 'application/json'},
body: JSON.stringify({jsonrpc: '2.0', method: 'call', params: {term: term}, id: Date.now()})
})
.then(function (res) { return res.json(); })
.then(function (data) {
var suggestions = data.result || [];
list.innerHTML = suggestions.map(function (item) {
var safe = String(item).replace(/"/g, '&quot;');
return '' + item +
'';
}).join('');
})
.catch(function () { list.innerHTML = ''; });
}, 250);
});
});

section.script:
document.addEventListener('DOMContentLoaded', function () {
var particlesContainer = document.getElementById('prqParticles');
if (!particlesContainer) return;

function createParticles() {
var colors = ['#d89a2b', '#e5a838', '#FFFFFF'];
for (var i = 0; i < 60; i++) {
var p = document.createElement('div');
var color = colors[Math.floor(Math.random() * colors.length)];
p.className = 'prq-particle';
p.style.background = color;
p.style.left = (40 + Math.random() * 20) + '%';
p.style.top = (25 + Math.random() * 20) + '%';
p.style.setProperty('--dx', (-120 + Math.random() * 240) + 'px');
p.style.setProperty('--dy', (-120 + Math.random() * 240) + 'px');
particlesContainer.appendChild(p);
(function (particle) {
setTimeout(function () { particle.remove(); }, 2200);
})(p);
}
}

createParticles();
setInterval(createParticles, 3000);
});
